import unreal
mesh = unreal.load_asset('/Game/Character/SK_Hunyuan')
sub = unreal.get_editor_subsystem(unreal.SkeletalMeshEditorSubsystem)
names = None
for attempt in ['via_subsystem','via_mesh','via_skeleton']:
    try:
        if attempt=='via_subsystem' and hasattr(sub,'get_bone_names'):
            names=[str(n) for n in sub.get_bone_names(mesh)]; break
        if attempt=='via_mesh' and hasattr(mesh,'get_bone_names'):
            names=[str(n) for n in mesh.get_bone_names()]; break
        if attempt=='via_skeleton':
            skel = unreal.load_asset('/Game/Character/Hunyuan_Mesh_Skeleton')
            if hasattr(skel,'get_bone_names'):
                names=[str(n) for n in skel.get_bone_names()]; break
    except Exception as e:
        print(attempt,'failed:',e)
print('BONES:', names)
if names is None:
    # last resort: num bones + name by index
    try:
        n = sub.get_num_bones(mesh)
        names=[str(sub.get_bone_name(mesh,i)) for i in range(n)]
        print('BONES2:', names)
    except Exception as e:
        print('idx failed', e)
# sockets on mesh
try:
    print('SOCKETS:', [str(s.socket_name) for s in mesh.get_editor_property('sockets')])
except Exception as e:
    print('sock err', e)
